// The postcondition is fundamentally unprovable: spec leaves r1.1/r2.1
    // unconstrained when r1.0/r2.0 == true (forall holds), so they may differ.
    // Best-effort: establish r1.0 == r2.0 and r1.1==r2.1 when !r1.0.
    if !r1.0 {
        assert(r1.0 == r2.0);
        assert(r1.1 == r2.1);
    }
